#[register_trap_handler(PAGE_FAULT)]
fn handle_page_fault(vaddr: VirtAddr, access_flags: MappingFlags, is_user: bool) -> bool {
    // 可恢复缺页是用户地址空间按需映射的一部分，避免污染测评串口输出。
    debug!(
        "Page fault at {:#x}, access_flags: {:#x?}",
        vaddr, access_flags
    );
    if !is_user && !is_accessing_user_memory() {
        return false;
    }

    let curr = current();
    if !curr
        .task_ext()
        .process_data()
        .aspace
        .lock()
        .handle_page_fault(vaddr, access_flags)
    {
        if is_user {
            // 用户态访问受保护页时应交给 SIGSEGV handler，而不是直接结束进程。
            curr.task_ext()
                .thread_data()
                .signal
                .send_signal(SignalInfo::new(Signo::SIGSEGV, SEGV_ACCERR as _));
            return true;
        }
        warn!(
            "{} ({:?}): segmentation fault at {:#x}, exit!",
            curr.id_name(),
            curr.task_ext().thread,
            vaddr
        );
        do_exit(SIGSEGV as _, true);
    }
    true
}

